DROP POLICY IF EXISTS Company members can manage chat messages ON public.chat_messages; CREATE POLICY Company members can manage chat messages ON public.chat_messages FOR ALL TO authenticated USING (company_id IN (SELECT company_id FROM public.company_members WHERE user_id = auth.uid() AND is_active = true)) WITH CHECK (company_id IN (SELECT company_id FROM public.company_members WHERE user_id = auth.uid() AND is_active = true));